     6→/**
     7→ * Hook to detect WebXR support and device capabilities
     8→ *
     9→ * This hook detects:
    10→ * - WebXR API support
    11→ * - VR headset availability
    12→ * - AR support
    13→ * - WebGL version support
    14→ * - Device type (mobile/desktop)
    15→ * - Performance characteristics
    16→ *
    17→ * @returns {VRCapabilities} Object containing device capability flags
    18→ *
    19→ * @example
    20→ * ```tsx
    21→ * const capabilities = useVRCapabilities();
    22→ *
    23→ * if (capabilities.hasWebXRSupport) {
    24→ *   // Render VR experience
    25→ * } else {
    26→ *   // Show fallback
    27→ * }
    28→ * ```
    29→ */
    30→export function useVRCapabilities(): VRCapabilities {
    31→  const [capabilities, setCapabilities] = useState<VRCapabilities>({
    32→    hasWebXRSupport: false,
    33→    hasVRHeadset: false,
    34→    hasARSupport: false,
    35→    hasHandTracking: false,
    36→    hasControllers: false,
    37→    displayMode: 'none',
    38→    supportsWebGL2: false,
    39→    isMobile: false,
    40→    devicePixelRatio: 1,
    41→  });
    42→
    43→  useEffect(() => {
    44→    const detectCapabilities = async () => {
    45→      const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(
    46→        navigator.userAgent
    47→      );
    48→      const devicePixelRatio = window.devicePixelRatio || 1;
    49→
    50→      // Check WebGL support
    51→      const canvas = document.createElement('canvas');
    52→      const gl = canvas.getContext('webgl2') || canvas.getContext('webgl');
    53→      const supportsWebGL2 = !!canvas.getContext('webgl2');
    54→
    55→      // Check max texture size for performance estimation
    56→      let maxTextureSize: number | undefined;
    57→      if (gl) {
    58→        maxTextureSize = gl.getParameter(gl.MAX_TEXTURE_SIZE);
    59→      }
